FOR UPDATE

mapper.update:
UPDATE t_voting_proxy_authorization
SET status = 'CONFIRMED', reviewed_by_user_id = #{reviewedByUserId},
    reviewed_at = #{reviewedAt}, review_note = #{reviewNote}, version = version + 1
WHERE authorization_id = #{authorizationId}
  AND tenant_id = #{tenantId}
  AND status = 'PENDING_REVIEW'
  AND registered_by_user_id <> #{reviewedByUserId}
  AND version = #{expectedVersion}

UPDATE t_voting_proxy_authorization
SET status = 'REJECTED', reviewed_by_user_id = #{reviewedByUserId},
    reviewed_at = #{reviewedAt}, review_note = #{reviewNote}, version = version + 1
WHERE authorization_id = #{authorizationId}
  AND tenant_id = #{tenantId}
  AND status = 'PENDING_REVIEW'
  AND registered_by_user_id <> #{reviewedByUserId}
  AND version = #{expectedVersion}

UPDATE t_voting_proxy_authorization
SET status = 'REVOKED', revoked_by_user_id = #{revokedByUserId},
    revoked_at = #{revokedAt}, revoke_reason = #{revokeReason}, version = version + 1
WHERE authorization_id = #{authorizationId}
  AND tenant_id = #{tenantId}
  AND status = 'CONFIRMED'
  AND version = #{expectedVersion}
  AND NOT EXISTS (
      SELECT 1 FROM t_paper_ballot ballot
      WHERE ballot.proxy_authorization_id = #{authorizationId}
  )

mapper.select:
SELECT EXISTS (
    SELECT 1 FROM t_paper_ballot
